import{_ as d,o as e,c as o,ag as a}from"./chunks/framework.DTiDeF2Q.js";const b=JSON.parse('{"title":"Git एलियास: अपने वर्जन कंट्रोल वर्कफ़्लो को सुव्यवस्थित करें | Dotfiles (HI)","titleTemplate":":title","description":"तेज़ कमिट, ब्रांच, डिफ, और रिमोट के लिए 80+ Git शेल एलियास। अपने दैनिक वर्जन कंट्रोल कार्यों को तेज़ करें।","frontmatter":{"title":"Git एलियास: अपने वर्जन कंट्रोल वर्कफ़्लो को सुव्यवस्थित करें","description":"तेज़ कमिट, ब्रांच, डिफ, और रिमोट के लिए 80+ Git शेल एलियास। अपने दैनिक वर्जन कंट्रोल कार्यों को तेज़ करें।","lang":"hi-IN","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Git एलियास: अपने वर्जन कंट्रोल वर्कफ़्लो को सुव्यवस्थित करें preview","canonical":"/hi/aliases/git/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Git एलियास: अपने वर्जन कंट्रोल वर्कफ़्लो को सुव्यवस्थित करें","pageType":"docs","schemaType":"WebPage","metaTitle":"Git एलियास | Dotfiles","permalink":"/hi/aliases/git/","sidebar":true,"meta":[{"name":"keywords","content":"git aliases, git shortcuts, git dotfiles, git commit alias, git branch alias, git push alias, shell, bash, zsh"},{"name":"twitter:card","content":"summary"},{"name":"twitter:description","content":"तेज़ कमिट, ब्रांच, डिफ, और रिमोट के लिए 80+ Git शेल एलियास।"},{"name":"twitter:title","content":"Git एलियास | Dotfiles"},{"name":"og:title","content":"Git एलियास | Dotfiles"},{"name":"og:description","content":"तेज़ कमिट, ब्रांच, डिफ, और रिमोट के लिए 80+ Git शेल एलियास।"},{"name":"og:image:alt","content":"Dotfiles - आपकी शेल लाइफ के लिए डिज़ाइन किया गया"},{"name":"og:locale","content":"hi_IN"}]},"headers":[],"relativePath":"hi/aliases/git/index.md","filePath":"hi/aliases/git/index.md","lastUpdated":1773010926000}'),c={name:"hi/aliases/git/index.md"};function r(i,t,h,l,s,n){return e(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="git-एलियास" tabindex="-1">Git एलियास <a class="header-anchor" href="#git-एलियास" aria-label="Permalink to &quot;Git एलियास&quot;">​</a></h1><p>शक्तिशाली शॉर्टकट के साथ अपने वर्जन कंट्रोल वर्कफ़्लो को सुव्यवस्थित करें।</p><h2 id="अवलोकन" tabindex="-1">अवलोकन <a class="header-anchor" href="#अवलोकन" aria-label="Permalink to &quot;अवलोकन&quot;">​</a></h2><p>Git एलियास अक्सर उपयोग किए जाने वाले Git कमांड के लिए शॉर्टकट बनाते हैं। <a href="https://github.com/sebastienrousseau/dotfiles" target="_blank" rel="noreferrer">Dotfiles</a> कॉन्फ़िगरेशन का हिस्सा, ये एलियास Chezmoi के माध्यम से स्वचालित रूप से लोड होते हैं।</p><p><code>git.aliases.sh</code> और <code>signing.aliases.sh</code> में परिभाषित, एलियास इंस्टॉल होने के बाद किसी भी Bash या Zsh सेशन में उपलब्ध हैं।</p><h2 id="संदर्भ" tabindex="-1">संदर्भ <a class="header-anchor" href="#संदर्भ" aria-label="Permalink to &quot;संदर्भ&quot;">​</a></h2><h3 id="कोर" tabindex="-1">कोर <a class="header-anchor" href="#कोर" aria-label="Permalink to &quot;कोर&quot;">​</a></h3><table tabindex="0"><thead><tr><th>एलियास</th><th>कमांड</th><th>विवरण</th></tr></thead><tbody><tr><td><code>g</code></td><td><code>git</code></td><td>git के लिए शॉर्टहैंड</td></tr><tr><td><code>gtp</code></td><td><code>git rev-parse --show-toplevel</code></td><td>रिपॉजिटरी की टॉप-लेवल डायरेक्टरी प्रिंट करें</td></tr><tr><td><code>grpa</code></td><td><code>git rev-parse --abbrev-ref HEAD</code></td><td>वर्तमान ब्रांच नाम प्रिंट करें</td></tr></tbody></table><h3 id="वर्किंग-एरिया" tabindex="-1">वर्किंग एरिया <a class="header-anchor" href="#वर्किंग-एरिया" aria-label="Permalink to &quot;वर्किंग एरिया&quot;">​</a></h3><table tabindex="0"><thead><tr><th>एलियास</th><th>कमांड</th><th>विवरण</th></tr></thead><tbody><tr><td><code>ga</code></td><td><code>git add</code></td><td>फाइलें स्टेज करें</td></tr><tr><td><code>gaa</code></td><td><code>git add --all</code></td><td>सभी परिवर्तन स्टेज करें</td></tr><tr><td><code>gad</code></td><td><code>git add .</code></td><td>वर्तमान डायरेक्टरी में सब कुछ स्टेज करें</td></tr><tr><td><code>gcl</code></td><td><code>git clone</code></td><td>रिपॉजिटरी क्लोन करें</td></tr><tr><td><code>gin</code></td><td><code>git init</code></td><td>नया Git रिपॉजिटरी आरंभ करें</td></tr><tr><td><code>gco</code></td><td><code>git checkout</code></td><td>ब्रांच स्विच करें</td></tr><tr><td><code>gcb</code></td><td><code>git checkout -b</code></td><td>नई ब्रांच बनाएं और स्विच करें</td></tr><tr><td><code>gst</code></td><td><code>git status</code></td><td>वर्किंग ट्री स्थिति दिखाएं</td></tr></tbody></table><h3 id="कमिट" tabindex="-1">कमिट <a class="header-anchor" href="#कमिट" aria-label="Permalink to &quot;कमिट&quot;">​</a></h3><table tabindex="0"><thead><tr><th>एलियास</th><th>कमांड</th><th>विवरण</th></tr></thead><tbody><tr><td><code>gc</code></td><td><code>git commit -a</code></td><td>सभी ट्रैक परिवर्तन कमिट करें</td></tr><tr><td><code>gca</code></td><td><code>git commit --amend</code></td><td>अंतिम कमिट में संशोधन करें</td></tr><tr><td><code>gcm</code></td><td><code>git commit --message</code></td><td>इनलाइन मैसेज के साथ कमिट करें</td></tr><tr><td><code>gcane</code></td><td><code>git commit --amend --no-edit</code></td><td>मैसेज बदले बिना कमिट में संशोधन करें</td></tr></tbody></table><h3 id="डिफ-और-हिस्ट्री" tabindex="-1">डिफ और हिस्ट्री <a class="header-anchor" href="#डिफ-और-हिस्ट्री" aria-label="Permalink to &quot;डिफ और हिस्ट्री&quot;">​</a></h3><table tabindex="0"><thead><tr><th>एलियास</th><th>कमांड</th><th>विवरण</th></tr></thead><tbody><tr><td><code>gd</code></td><td><code>git diff</code></td><td>अनस्टेज परिवर्तन दिखाएं</td></tr><tr><td><code>gdh</code></td><td><code>git diff HEAD</code></td><td>अंतिम कमिट के बाद सभी परिवर्तन दिखाएं</td></tr><tr><td><code>gdstaged</code></td><td><code>git diff --staged</code></td><td>स्टेज परिवर्तन दिखाएं</td></tr><tr><td><code>gl</code></td><td><code>git log --since=&quot;last month&quot; --oneline</code></td><td>पिछले महीने का वन-लाइन लॉग</td></tr><tr><td><code>glg</code></td><td><code>git log --graph --all --oneline --decorate</code></td><td>सभी ब्रांच का ग्राफ लॉग</td></tr></tbody></table><h3 id="ब्रांच" tabindex="-1">ब्रांच <a class="header-anchor" href="#ब्रांच" aria-label="Permalink to &quot;ब्रांच&quot;">​</a></h3><table tabindex="0"><thead><tr><th>एलियास</th><th>कमांड</th><th>विवरण</th></tr></thead><tbody><tr><td><code>gb</code></td><td><code>git branch</code></td><td>लोकल ब्रांच सूचीबद्ध करें</td></tr><tr><td><code>gbd</code></td><td><code>git branch -d</code></td><td>मर्ज ब्रांच हटाएं</td></tr><tr><td><code>gbr</code></td><td><code>git branch -r</code></td><td>रिमोट ब्रांच सूचीबद्ध करें</td></tr><tr><td><code>gswb</code></td><td><code>git switch</code></td><td>ब्रांच स्विच करें (मॉडर्न)</td></tr></tbody></table><h3 id="रिमोट-और-push-pull" tabindex="-1">रिमोट और Push/Pull <a class="header-anchor" href="#रिमोट-और-push-pull" aria-label="Permalink to &quot;रिमोट और Push/Pull&quot;">​</a></h3><table tabindex="0"><thead><tr><th>एलियास</th><th>कमांड</th><th>विवरण</th></tr></thead><tbody><tr><td><code>gf</code></td><td><code>git fetch</code></td><td>रिमोट से फेच करें</td></tr><tr><td><code>gp</code></td><td><code>git pull</code></td><td>रिमोट से पुल करें</td></tr><tr><td><code>gph</code></td><td><code>git push</code></td><td>रिमोट पर पुश करें</td></tr><tr><td><code>gpo</code></td><td><code>git push origin</code></td><td>origin पर पुश करें</td></tr><tr><td><code>gpb</code></td><td><code>git push --set-upstream origin $(git branch --show-current)</code></td><td>वर्तमान ब्रांच के लिए पुश और अपस्ट्रीम सेट करें</td></tr></tbody></table><h3 id="रिवर्ट-और-रीसेट" tabindex="-1">रिवर्ट और रीसेट <a class="header-anchor" href="#रिवर्ट-और-रीसेट" aria-label="Permalink to &quot;रिवर्ट और रीसेट&quot;">​</a></h3><table tabindex="0"><thead><tr><th>एलियास</th><th>कमांड</th><th>विवरण</th></tr></thead><tbody><tr><td><code>grev</code></td><td><code>git revert</code></td><td>कमिट रिवर्ट करें</td></tr><tr><td><code>grb</code></td><td><code>git rebase</code></td><td>वर्तमान ब्रांच रीबेस करें</td></tr><tr><td><code>grbk</code></td><td><code>git reset --soft HEAD^</code></td><td>अंतिम कमिट अनडू करें, परिवर्तन स्टेज रखें</td></tr><tr><td><code>gresh</code></td><td><code>git reset --hard HEAD~1</code></td><td>पिछले कमिट पर हार्ड रीसेट</td></tr></tbody></table><h3 id="साइनिंग-और-सुरक्षा" tabindex="-1">साइनिंग और सुरक्षा <a class="header-anchor" href="#साइनिंग-और-सुरक्षा" aria-label="Permalink to &quot;साइनिंग और सुरक्षा&quot;">​</a></h3><table tabindex="0"><thead><tr><th>एलियास</th><th>कमांड</th><th>विवरण</th></tr></thead><tbody><tr><td><code>enable-signing</code></td><td><em>(इंटरैक्टिव विज़ार्ड)</em></td><td>GPG या SSH कमिट साइनिंग कॉन्फ़िगर करें</td></tr><tr><td><code>verify-signatures</code></td><td><code>git log --show-signature -n 10</code></td><td>अंतिम 10 कमिट के सिग्नेचर वेरिफाई करें</td></tr><tr><td><code>check-signing</code></td><td><code>git config --list | grep &quot;gpg|signing&quot;</code></td><td>वर्तमान साइनिंग कॉन्फ़िगरेशन जांचें</td></tr></tbody></table>',22)])])}const u=d(c,[["render",r]]);export{b as __pageData,u as default};
